import React, { useEffect, useState } from "react";
import {
  Box,
  Button,
  Typography,
  Card,
  CardContent,
  Divider,
  CircularProgress,
  Avatar,
  IconButton,
  Tooltip,
} from "@mui/material";
import { Link as RouterLink, useNavigate } from "react-router-dom";
import DeleteIcon from "@mui/icons-material/Delete";
import Footer from "../../components/Footer";

interface Novedad {
  Id_Novedad: number;
  Descripcion: string;
  Fecha: string;
  Id_Empleado: number;
}

export default function Tablon() {
  const [novedades, setNovedades] = useState<Novedad[]>([]);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState<number | null>(null);

  // Función para cargar novedades
  const fetchNovedades = () => {
    setLoading(true);
    fetch("http://localhost:4000/api/novedad/tablon")
      .then((res) => res.json())
      .then((data) => {
        setNovedades(data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  useEffect(() => {
    fetchNovedades();
    const interval = setInterval(fetchNovedades, 10000); // cada 10 segundos
    return () => clearInterval(interval);
  }, []);

  // Eliminar novedad
  const handleDelete = async (id: number) => {
    setDeleting(id);
    try {
      await fetch(`http://localhost:4000/api/novedad/tablon/${id}`, {
        method: "DELETE",
      });
      setNovedades((prev) => prev.filter((n) => n.Id_Novedad !== id));
    } catch {
      // Manejo de error opcional
    } finally {
      setDeleting(null);
    }
  };

  return (
    <Box
      sx={{
        minHeight: "100vh",
        backgroundColor: "#d9d6d6ff",
        display: "flex",
        flexDirection: "column",
        overflowX: "hidden",
      }}
    >
      {/* Encabezado */}
      <Box
        sx={{
          py: 4,
          px: 3,
          backgroundColor: "#1c1c1c",
          boxShadow: "0 2px 8px rgba(0, 0, 0, 0.3)",
        }}
      >
        <Typography
          variant="h3"
          sx={{
            fontFamily: "Tektur, sans-serif",
            fontWeight: 700,
            color: "#ffffff",
            userSelect: "none",
          }}
        >
          <span style={{ color: "#FF6B00" }}>360</span>{" "}
          <span style={{ color: "#ffffff" }}>Sueldos</span>
        </Typography>
      </Box>

      {/* Botón Volver */}
      <Box sx={{ display: "flex", justifyContent: "flex-end", mt: 3, px: 4 }}>
        <Button
          component={RouterLink}
          to="/rrhh-principal"
          variant="contained"
          sx={{
            backgroundColor: "#1565C0",
            marginRight: 3,
            color: "#ffffff",
            width: 180,
            letterSpacing: 3,
            fontSize: 20,
            borderRadius: 3,
            mr: 5,
            fontFamily: "Tektur, sans-serif",
            fontWeight: 500,
            textTransform: "none",
          }}
        >
          Volver
        </Button>
      </Box>

      {/* Tarjetas de mensajes */}
      <Box
        sx={{
          flexGrow: 1,
          px: 3,
          mt: 4,
          display: "flex",
          flexDirection: "column",
          gap: 4,
          maxWidth: "600px",
          mx: "auto",
          mb: 6,
        }}
      >
        {loading ? (
          <CircularProgress sx={{ mx: "auto", mt: 6 }} />
        ) : novedades.length === 0 ? (
          <Typography
            variant="h6"
            sx={{
              textAlign: "center",
              color: "#888",
              fontFamily: "Tektur, sans-serif",
              mt: 6,
            }}
          >
            No hay novedades publicadas.
          </Typography>
        ) : (
          novedades.map((novedad) => (
            <Card
              key={novedad.Id_Novedad}
              sx={{
                borderRadius: 4,
                backgroundColor: "#fff",
                boxShadow: "0 4px 16px rgba(0,0,0,0.10)",
                transition: "transform 0.2s, box-shadow 0.2s",
                "&:hover": {
                  transform: "translateY(-3px) scale(1.01)",
                  boxShadow: "0 8px 32px rgba(0,0,0,0.16)",
                },
                px: 2,
                pt: 2,
                pb: 1,
                position: "relative",
                width: 700,
                minHeight: 260,
                maxWidth: "100%",
                display: "flex",
                flexDirection: "column",
                justifyContent: "space-between",
              }}
            >
              <Box sx={{ display: "flex", alignItems: "center", mb: 1 }}>
                <Avatar sx={{ bgcolor: "#1976d2", mr: 2 }}>
                  {/* Iniciales RRHH */}R
                </Avatar>
                <Box>
                  <Typography
                    variant="subtitle1"
                    sx={{
                      fontWeight: 700,
                      fontFamily: "Tektur, sans-serif",
                      color: "#1976d2",
                    }}
                  >
                    RRHH
                  </Typography>
                  <Typography
                    variant="caption"
                    sx={{ color: "#888", fontFamily: "Tektur, sans-serif" }}
                  >
                    {new Date(novedad.Fecha).toLocaleString()}
                  </Typography>
                </Box>
                <Box sx={{ flexGrow: 1 }} />
                <Tooltip title="Eliminar novedad">
                  <span>
                    <IconButton
                      color="error"
                      size="small"
                      disabled={deleting === novedad.Id_Novedad}
                      onClick={() => handleDelete(novedad.Id_Novedad)}
                    >
                      <DeleteIcon />
                    </IconButton>
                  </span>
                </Tooltip>
              </Box>
              <Divider sx={{ mb: 2 }} />
              <Typography
                variant="body1"
                sx={{
                  fontFamily: "Tektur, sans-serif",
                  color: "#333",
                  fontSize: 18,
                  mb: 1,
                }}
              >
                {novedad.Descripcion}
              </Typography>
            </Card>
          ))
        )}
      </Box>

      <Footer />
    </Box>
  );
}
